import java.util.*;class Player{static int W,H,EX;static int[][]T,LK;static int[]DX={0,1,0,-1},DY={-1,0,1,0},OP={2,3,0,1};static int[][]RG={{0},{1},{2,3},{3,2},{4,5},{5,4},{6,7,8,9},{7,8,9,6},{8,9,6,7},{9,6,7,8},{10,11,12,13},{11,12,13,10},{12,13,10,11},{13,10,11,12}};static Map<Integer,Integer>[]RM;static Map<Integer,Integer>rot=new HashMap<>();static List<int[]>plan=new ArrayList<>();static boolean dfs(int x,int y,int e){if(y>=H)return x==EX;if(x<0||x>=W||y<0)return false;int o=T[y][x],k=y*W+x;int[]cs=LK[y][x]==1?new int[]{rot.getOrDefault(k,o)}:RG[o];for(int c:cs){if(!RM[c].containsKey(e))continue;int ex=RM[c].get(e),nx=x+DX[ex],ny=y+DY[ex],ne=OP[ex];boolean had=rot.containsKey(k);int pv=had?rot.get(k):0;rot.put(k,c);if(dfs(nx,ny,ne)){if(c!=o)plan.add(new int[]{x,y,c});return true;}if(had)rot.put(k,pv);else rot.remove(k);}return false;}@SuppressWarnings("unchecked")public static void main(String[]a){RM=new Map[14];for(int i=0;i<14;i++)RM[i]=new HashMap<>();RM[1].put(0,2);RM[1].put(1,2);RM[1].put(3,2);RM[2].put(1,3);RM[2].put(3,1);RM[3].put(0,2);RM[4].put(0,3);RM[4].put(1,2);RM[5].put(0,1);RM[5].put(3,2);RM[6].put(1,3);RM[6].put(3,1);RM[7].put(0,2);RM[7].put(1,2);RM[8].put(3,2);RM[8].put(1,2);RM[9].put(0,2);RM[9].put(3,2);RM[10].put(0,3);RM[11].put(0,1);RM[12].put(1,2);RM[13].put(3,2);var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();T=new int[H][W];LK=new int[H][W];for(int y=0;y<H;y++)for(int x=0;x<W;x++){int v=s.nextInt();T[y][x]=Math.abs(v);LK[y][x]=v<0?1:0;}EX=s.nextInt();var Q=new ArrayList<String>();Map<String,Integer>EM=Map.of("TOP",0,"RIGHT",1,"LEFT",3);for(;;){int xi=s.nextInt(),yi=s.nextInt();int ent=EM.get(s.next());int R=s.nextInt();for(int i=0;i<R;i++){s.nextInt();s.nextInt();s.next();}if(Q.isEmpty()){rot.clear();plan.clear();if(dfs(xi,yi,ent))for(var st:plan){int o=T[st[1]][st[0]],r=-1;int[]g=RG[o];for(int i=0;i<g.length;i++)if(g[i]==st[2]){r=i;break;}if(r<=0)continue;if(r<=2)for(int i=0;i<r;i++)Q.add(st[0]+" "+st[1]+" RIGHT");else Q.add(st[0]+" "+st[1]+" LEFT");T[st[1]][st[0]]=st[2];}}System.out.println(Q.isEmpty()?"WAIT":Q.remove(0));}}}
